<template>  <div class="content  animate__animated  animate__fadeIn">    <div class="HomeTitle">      <h1 style="color: var(--c-text-666)">- 分类 "{{ route.query?.name }}" 下的文章 -</h1>      <h3 style="color: var(--c-text-666)">{{ userStore.userInfo?.homeIntro }}</h3>    </div>    <div v-show="!articleList.list.length" class="empty">      <NEmpty description="该分类还没有文章！" size="large">      </NEmpty>    </div>    <div class="itemContent">      <div v-for="item in articleList.list" :key="item._id"           :class="`section wow animate__animated animate__fadeInUp`"           data-wow-duration="0.6s"           data-wow-iteration="1" data-wow-offset="1" @click="gotoDetail(item._id)">        <div class="card">          <div class="card-img">            <img v-lazy="item.cover"/>          </div>          <div class="titleInfo">            <div class="title">{{ item.title }}</div>            <div>              <div class="divider">                <NDivider/>              </div>              <div class="info">                <!--            HappyOutline-->                <div class="name">                  <NIcon size="16">                    <PersonOutline></PersonOutline>                  </NIcon>                  {{ item.author }}                </div>                <div class="time">                  <NIcon size="16">                    <TimeOutline></TimeOutline>                  </NIcon>                  {{ formatTime(item.created) }}                </div>                <div class="see">                  <NIcon size="16">                    <EyeOutline></EyeOutline>                  </NIcon>                  {{ item.browse }}                </div>              </div>            </div>          </div>        </div>      </div>    </div>  </div></template><script lang='ts' setup>import {NEmpty, NDivider, NIcon} from 'naive-ui'import {PersonOutline, TimeOutline, EyeOutline} from '@vicons/ionicons5'import {Icon} from "@vicons/utils/lib";import {onMounted, reactive, ref, computed, watch} from 'vue';import WOW from "wow.js";import dayjs from 'dayjs'import {getCategroyItem} from "@/api/article";import {useRoute, useRouter} from "vue-router";import useUser from "@/stores/useUser";const userStore = useUser()const route = useRoute()const router = useRouter()const articleList = reactive<any>({list: []})const gotoDetail = (id) => {  router.push(`/article/${id}`)}const formatTime = computed((item) => () => {  return dayjs(item).format('YYYY-MM-DD')})watch(() => route.query.id, async (val) => {  if (val) {    const res = await getCategroyItem(val)    if (res.code === 200) {      articleList.list = res.data    }  }})onMounted(async () => {  if (route.query.id) {    const res = await getCategroyItem(route.query.id)    if (res.code === 200) {      articleList.list = res.data    }  }  let wow = new WOW({    boxClass: "wow",    animateClass: "animated",    offset: 0,    mobile: true,    live: true,    callback: function () {    },    scrollContainer: false,    resetAnimation: true,  })  wow.init()})</script><style lang="less" scoped>:deep(.n-pagination .n-pagination-item.n-pagination-item--button) {  background: transparent;  border: #fffccc;}.content {  min-height: calc(100vh - 120px);  overflow: hidden;  border-radius: 2px;  box-shadow: 0 1px 3px rgb(0 0 0 / 5%);  background: var(--c-f1f3f4);  .HomeTitle {    min-height: 120px;    padding: 20px;    text-align: center;    background-color: var(--c-f9f9f930);  }  .itemContent {    background: var(--c-f1f3f4);    padding: 20px;  }  .card {    //height: 230px;    margin-bottom: 20px;    display: grid;    //grid-template-columns: 300px 1fr;    gap: 20px;    border-radius: 5px;    transition: all .5s;    box-shadow: rgba(0, 0, 0, 0.1) 0 0 5px 0, rgba(0, 0, 0, 0.1) 0 0 1px 0;    cursor: url('@/assets/link.cur'), pointer;    background: var(--c-bg-bodyFFF);    &:hover {      transform: translateY(-10px);      box-shadow: 0 8px 10px rgba(96, 206, 174, 0.3)    }    &:hover img {      transform: scale(1.1);    }    .card-img {      height: 250px;      overflow: hidden;      display: flex;      justify-content: center;      align-items: center;      border-radius: 5px 5px 0 0;      box-shadow: rgba(0, 0, 0, 0.05) 0px 1px 2px 0px;      img {        width: 100%;        transition: all .5s;      }    }    .titleInfo {      display: grid;      align-content: space-between;      .title {        font-size: 18px;        color: var(--c-text-666);        text-align: left;        padding: 15px 20px;        white-space: nowrap;        overflow: hidden;        text-overflow: ellipsis;        -webkit-line-clamp: 1;        -webkit-box-orient: vertical;      }      .description {        padding: 10px 40px;        span {          text-align: left;          font-size: 12px;          color: var(--c-text-777);          overflow: hidden;          text-overflow: ellipsis;          -webkit-line-clamp: 2;          display: -webkit-box;          -webkit-box-orient: vertical;        }      }      .divider {        padding: 0 10px;        :deep(.n-divider:not(.n-divider--dashed) .n-divider__line) {          //background: var(--c-divider);          background: var(--c-divider);          margin-bottom: 10px;        }        :deep(.n-divider:not(.n-divider--vertical)) {          margin: 0;        }      }      .info {        display: grid;        align-items: center;        grid-template-columns: 1fr 1fr 1fr;        //gap: 10px;        padding-bottom: 10px;        .name, .time, .see {          padding-left: 20px;          display: flex;          justify-content: center;          align-items: center;          gap: 5px;          font-size: 12px;          color: var(--c-text-666);        }      }    }  }  .pages {    display: flex;    justify-content: center;    align-items: flex-end;    position: sticky;    bottom: 0;  }  .empty {    display: flex;    justify-content: center;    align-items: center;    min-height: calc(100vh - 120px);  }  .icon {    width: 5em;    height: 5em;    vertical-align: -0.15em;    fill: currentColor;    overflow: hidden;  }}@media screen and (max-width: 750px) {  .content {    display: grid;    gap: 10px;    grid-template-columns: 1fr;  }  .content .card {    height: 330px;    margin-bottom: 40px;    padding: 3px;    display: grid;    grid-template-columns: 1fr;    flex-wrap: wrap;    gap: 10px;    border-radius: 10px;    transition: all .5s;    box-shadow: rgba(0, 0, 0, 0.1) 0 0 5px 0, rgba(0, 0, 0, 0.1) 0 0 1px 0;    cursor: url('@/assets/link.cur'), pointer;    .titleInfo {      .title {        padding: 0 20px;      }    }    .card-img {      overflow: hidden;      display: flex;      justify-content: center;      align-items: center;      border-radius: 10px;      height: 200px;      box-shadow: rgba(0, 0, 0, 0.05) 0px 1px 2px 0px;      position: relative;      img {        position: absolute;        top: 50%;        left: 50%;        //width: 100%;        //height: 100%;        transform: translate(-50%, -50%);        transition: all .5s;        //opacity: .8;      }    }  }}</style>